mapper.select:
SELECT MULTI_TYPE, MULTI_CD, MULTI_CONTENTS FROM STOCLANG WHERE GATE_CD = '100' #{ses.gateCd}
AND SCREEN_ID = #{screenId} AND LANG_CD = 'KO' #{langCd}
AND DEL_FLAG = '0' AND MULTI_TYPE = 'M' AND FORM_GRID_ID = 'msg' ORDER BY MULTI_CD

SELECT SCAC.ACTION_CD, ACPF.ACTION_PROFILE_CD FROM STOCACPF ACPF INNER JOIN STOCSCAC SCAC ON (ACPF.GATE_CD = SCAC.GATE_CD AND ACPF.SCREEN_ID = SCAC.SCREEN_ID AND ACPF.ACTION_CD = SCAC.ACTION_CD) WHERE ACPF.GATE_CD = '100' #{ses.gateCd}
AND ACPF.SCREEN_ID = #{screenId}
AND ACPF.ACTION_PROFILE_CD = #{actionAuthCd}
AND ACPF.DEL_FLAG = '0' AND SCAC.DEL_FLAG = '0'

select.if:
SELECT TMPL_MENU_CD FROM STOCMUTM WHERE DEL_FLAG = '0'
AND MODULE_TYPE = #{moduleType}
AND TMPL_MENU_GROUP_CD IN (SELECT TMPL_MENU_GROUP_CD FROM STOCMUGR WHERE GATE_CD = '100' #{ses.gateCd}
AND DEL_FLAG = 0 AND MENU_GROUP_CD IN (SELECT MENU_GROUP_CD FROM STOCAUMP WHERE GATE_CD = '100' #{ses.gateCd}
AND AUTH_CD = #{ses.grantedAuthCd} AND DEL_FLAG = 0)) START WITH SCREEN_ID LIKE #{screenId}'%' CONNECT BY PRIOR HIGH_TMPL_MENU_CD = TMPL_MENU_CD ORDER BY LEVEL DESC

WITH cte ( TMPL_MENU_CD, HIGH_TMPL_MENU_CD, lvl ) AS (SELECT TMPL_MENU_CD, HIGH_TMPL_MENU_CD, 1 AS lvl FROM STOCMUTM WHERE DEL_FLAG = '0'
AND MODULE_TYPE = #{moduleType}
AND SCREEN_ID = #{screenId} AND TMPL_MENU_GROUP_CD IN (SELECT TMPL_MENU_GROUP_CD FROM STOCMUGR WHERE GATE_CD = '100' #{ses.gateCd}
AND DEL_FLAG = 0 AND MENU_GROUP_CD IN (SELECT MENU_GROUP_CD FROM STOCAUMP WHERE GATE_CD = '100' #{ses.gateCd}
AND AUTH_CD = #{ses.grantedAuthCd} AND DEL_FLAG = 0)) UNION ALL SELECT a.TMPL_MENU_CD, a.HIGH_TMPL_MENU_CD, lvl + 1 FROM STOCMUTM a, cte b WHERE DEL_FLAG = '0'
AND MODULE_TYPE = #{moduleType}
AND a.TMPL_MENU_CD = b.HIGH_TMPL_MENU_CD AND TMPL_MENU_GROUP_CD IN (SELECT TMPL_MENU_GROUP_CD FROM STOCMUGR WHERE GATE_CD = '100' #{ses.gateCd}
AND DEL_FLAG = 0 AND MENU_GROUP_CD IN (SELECT MENU_GROUP_CD FROM STOCAUMP WHERE GATE_CD = '100' #{ses.gateCd}
AND AUTH_CD = #{ses.grantedAuthCd} AND DEL_FLAG = 0))) SELECT TMPL_MENU_CD FROM cte order by lvl desc

SELECT TMPL_MENU_CD FROM STOCMUTM WHERE DEL_FLAG = '0'
AND MODULE_TYPE = #{moduleType}
AND TMPL_MENU_GROUP_CD IN (SELECT TMPL_MENU_GROUP_CD FROM STOCMUGR WHERE GATE_CD = '100' #{ses.gateCd}
AND DEL_FLAG = 0 AND MENU_GROUP_CD IN (SELECT MENU_GROUP_CD FROM STOCAUMP WHERE GATE_CD = '100' #{ses.gateCd}
AND AUTH_CD = #{ses.grantedAuthCd} AND DEL_FLAG = 0)) START WITH SCREEN_ID = #{screenId} CONNECT BY PRIOR HIGH_TMPL_MENU_CD = TMPL_MENU_CD ORDER BY LEVEL DESC

WITH cte ( TMPL_MENU_CD, HIGH_TMPL_MENU_CD, lvl ) AS (SELECT TMPL_MENU_CD, HIGH_TMPL_MENU_CD, 1 AS lvl FROM STOCMUTM WHERE DEL_FLAG = '0'
AND MODULE_TYPE = #{moduleType}
AND SCREEN_ID = #{screenId} AND TMPL_MENU_GROUP_CD IN (SELECT TMPL_MENU_GROUP_CD FROM STOCMUGR WHERE GATE_CD = '100' #{ses.gateCd}
AND DEL_FLAG = 0 AND MENU_GROUP_CD IN (SELECT MENU_GROUP_CD FROM STOCAUMP WHERE GATE_CD = '100' #{ses.gateCd}
AND AUTH_CD = #{ses.grantedAuthCd} AND DEL_FLAG = 0)) UNION ALL SELECT a.TMPL_MENU_CD, a.HIGH_TMPL_MENU_CD, lvl + 1 FROM STOCMUTM a, cte b WHERE DEL_FLAG = '0'
AND MODULE_TYPE = #{moduleType}
AND a.TMPL_MENU_CD = b.HIGH_TMPL_MENU_CD AND TMPL_MENU_GROUP_CD IN (SELECT TMPL_MENU_GROUP_CD FROM STOCMUGR WHERE GATE_CD = '100' #{ses.gateCd}
AND DEL_FLAG = 0 AND MENU_GROUP_CD IN (SELECT MENU_GROUP_CD FROM STOCAUMP WHERE GATE_CD = '100' #{ses.gateCd}
AND AUTH_CD = #{ses.grantedAuthCd} AND DEL_FLAG = 0))) SELECT TMPL_MENU_CD FROM cte order by lvl desc

mapper.select:
SELECT SCREEN_ID AS "screenId" ,FORM_GRID_ID AS "formId" ,COLUMN_ID AS "columnId" , 'KO' #{langCd} AS "languageCd" ,MULTI_CD AS "multiCd" ,MULTI_CONTENTS AS "multiContents" ,MULTI_TYPE AS "multiType" ,DATA_TYPE AS "dataType" ,ALIGNMENT_TYPE AS "alignmentType" ,COLUMN_TYPE AS "columnType" ,(CASE WHEN EDIT_FLAG = '1' THEN 'true' ELSE 'false' END) AS "editable" ,(CASE WHEN BACK_COLOR_TEXT = 'NULL' THEN '' ELSE BACK_COLOR_TEXT END) AS "backColor" ,(DISABLE_FLAG, '0') AS "disableFlag" ,(INVISIBLE_FLAG, '0') AS "invisibleFlag" ,COMMON_ID AS "commonId" ,(SELECT (SCRN.PANEL_USE_FLAG, '0') FROM STOCSCRN SCRN WHERE SCRN.GATE_CD = LANG.GATE_CD AND SCRN.SCREEN_ID = LANG.SCREEN_ID AND SCRN.DEL_FLAG = '0') AS "panelVisible" ,(SELECT (SCRN.SHRINK_TO_FIT, '0') FROM STOCSCRN SCRN WHERE SCRN.GATE_CD = LANG.GATE_CD AND SCRN.SCREEN_ID = LANG.SCREEN_ID AND SCRN.DEL_FLAG = '0') AS "shrinkToFit" ,LANG.ON_NUMBER_KR AS "onNumberKr" ,LANG.CURRENCY_TEXT AS "currencyText" ,LANG.MASK_TYPE AS "maskType" ,(SELECT SCRN.APPROVAL_TYPE FROM STOCSCRN SCRN WHERE SCRN.GATE_CD = LANG.GATE_CD AND SCRN.SCREEN_ID = LANG.SCREEN_ID AND SCRN.DEL_FLAG = '0') AS "approvalType"
,TO_CHAR(MAX_LENGTH) AS "maxLength" ,TO_CHAR(COLUMN_WIDTH) AS "width"
,CAST(MAX_LENGTH AS NVARCHAR(MAX)) AS "maxLength" ,CAST(CAST(COLUMN_WIDTH AS INT) AS NVARCHAR(MAX)) AS "width"
FROM STOCLANG LANG WHERE GATE_CD = '100' #{ses.gateCd}
AND DEL_FLAG = '0' AND USE_FLAG = '1' AND SCREEN_ID = #{screenId} AND LANG_CD = 'KO' #{langCd}
AND MULTI_TYPE IN ('F', 'G') ORDER BY FORM_GRID_ID

