mapper.select:
		SELECT MULTI_NM FROM (


		   AND TMPL_MENU_CD = #{tmplMenuCd}
		 ORDER BY REG_DATE DESC
		) A

           WHERE ROWNUM = 1

SELECT (EXCEL_OPTION, 'A') AS EXCEL_OPTION FROM STOCSCRN WHERE GATE_CD = '100' #{ses.gateCd}
AND SCREEN_ID = #{screenId} AND DEL_FLAG != 1
AND ROWNUM = 1

        SELECT MASK.MASK_APPROVAL
             , MASK.SCREEN_CRUD
          FROM STOCMASK MASK
         WHERE MASK.GATE_CD = #{ses.gateCd}
		   AND MASK.ACCESS_DATE = #{accessDate}
           AND MASK.SCREEN_ID = #{screenId}
           AND MASK.USER_ID = #{ses.userId}
           AND MASK.MASK_APPROVAL = 'E'
		   AND MASK.DEL_FLAG = '0'

SELECT APPROVAL_TYPE
  FROM STOCSCRN
 WHERE GATE_CD = #{ses.gateCd}
   AND SCREEN_ID = #{screenId}
   AND DEL_FLAG = '0'
